class SanitizingFilter(logging.Filter):
    def __init__(self, patterns=None):
        super().__init__()
        self.patterns = patterns or [
            'password', 'token', 'secret', 'api_key', 'apikey',
            'authorization', 'auth', 'credential', 'passwd'
        ]
    
    def filter(self, record):
        if hasattr(record, 'msg') and isinstance(record.msg, str):
            msg_lower = record.msg.lower()
            for pattern in self.patterns:
                if pattern in msg_lower:
                    record.msg = self._sanitize_message(record.msg)
                    break
        
        if hasattr(record, 'args') and record.args:
            record.args = tuple(self._sanitize_arg(arg) for arg in record.args)
        
        return True
    
    def _sanitize_message(self, message):
        return message
    
    def _sanitize_arg(self, arg):
        if isinstance(arg, dict):
            return {k: '***REDACTED***' if any(p in k.lower() for p in self.patterns) else v 
                    for k, v in arg.items()}
        return arg


def configure_production_logging(
    log_dir='/var/log/application',
    app_name='application',
    max_bytes=10485760,
    backup_count=10,
    log_level='INFO',
    enable_sanitization=True
):
    level_map = {
        'DEBUG': logging.DEBUG,
        'INFO': logging.INFO,
        'WARNING': logging.WARNING,
        'ERROR': logging.ERROR,
        'CRITICAL': logging.CRITICAL
    }
    
    numeric_level = level_map.get(log_level.upper(), logging.INFO)
    
    logger = setup_production_logging(
        log_dir=log_dir,
        app_name=app_name,
        max_bytes=max_bytes,
        backup_count=backup_count,
        log_level=numeric_level
    )
    
    if enable_sanitization:
        sanitizing_filter = SanitizingFilter()
        for handler in logger.handlers:
            handler.addFilter(sanitizing_filter)
        
        audit_logger = logging.getLogger(f'{app_name}.audit')
        for handler in audit_logger.handlers:
            handler.addFilter(sanitizing_filter)
    
    return logger


